import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic(); // reads ANTHROPIC_API_KEY from env

const SYSTEM = `You are a concise React code reviewer.
Rules:
- Identify the most important issue first.
- Provide the corrected code snippet immediately after.
- Do not explain unless asked.
- Use React 18+ conventions.`;

const history = [];

async function chat(userMessage) {
  history.push({ role: "user", content: userMessage });

  const response = await client.messages.create({
    model: "claude-opus-4-5",
    max_tokens: 512,
    system: SYSTEM,
    messages: history,
  });

  const assistantText = response.content[0].text;
  history.push({ role: "assistant", content: assistantText });
  return assistantText;
}

// Turn 1
console.log(await chat("Review this component: function Btn({ onClick }) { return <button onClick={onClick}>Click</button>; }"));

// Turn 2 — model retains context from turn 1
console.log(await chat("Now add an isDisabled prop."));
